705: func virtualServiceDestinationHosts(v *networking.VirtualService) []string {
706: 	if v == nil {
707: 		return nil
708: 	}
709: 
710: 	var out []string
711: 
712: 	for _, h := range v.Http {
713: 		for _, r := range h.Route {
714: 			if r.Destination != nil {
715: 				out = append(out, r.Destination.Host)
716: 			}
717: 		}
718: 		if h.Mirror != nil {
719: 			out = append(out, h.Mirror.Host)
720: 		}
721: 	}
722: 	for _, t := range v.Tcp {
723: 		for _, r := range t.Route {
724: 			if r.Destination != nil {
725: 				out = append(out, r.Destination.Host)
726: 			}
727: 		}
