740: // GatewayServices returns the set of services which are referred from the proxy gateways.
741: func (ps *PushContext) GatewayServices(proxy *Proxy) []*Service {
742: 	svcs := proxy.SidecarScope.services
743: 
744: 	// MergedGateway will be nil when there are no configs in the
745: 	// system during initial installation.
746: 	if proxy.MergedGateway == nil {
747: 		return nil
748: 	}
749: 
750: 	// host set.
751: 	hostsFromGateways := sets.New()
752: 	for _, gw := range proxy.MergedGateway.GatewayNameForServer {
753: 		for _, vsConfig := range ps.VirtualServicesForGateway(proxy.ConfigNamespace, gw) {
754: 			vs, ok := vsConfig.Spec.(*networking.VirtualService)
755: 			if !ok { // should never happen
756: 				log.Errorf("Failed in getting a virtual service: %v", vsConfig.Labels)
757: 				return svcs
758: 			}
759: 
760: 			for _, host := range virtualServiceDestinationHosts(vs) {
761: 				hostsFromGateways.Insert(host)
762: 			}
763: 		}
764: 	}
765: 
766: 	hostsFromMeshConfig := getHostsFromMeshConfig(ps)
767: 	hostsFromGateways.Merge(hostsFromMeshConfig)
768: 
769: 	log.Debugf("GatewayServices: gateway %v is exposing these hosts:%v", proxy.ID, hostsFromGateways)
770: 
771: 	gwSvcs := make([]*Service, 0, len(svcs))
772: 
773: 	for _, s := range svcs {
774: 		svcHost := string(s.Hostname)
775: 
776: 		if _, ok := hostsFromGateways[svcHost]; ok {
777: 			gwSvcs = append(gwSvcs, s)
778: 		}
779: 	}
780: 
781: 	log.Debugf("GatewayServices:: gateways len(services)=%d, len(filtered)=%d", len(svcs), len(gwSvcs))
782: 
783: 	return gwSvcs
784: }
