861: // IsServiceVisible returns true if the input service is visible to the given namespace.
862: func (ps *PushContext) IsServiceVisible(service *Service, namespace string) bool {
863: 	if service == nil {
864: 		return false
865: 	}
866: 
867: 	ns := service.Attributes.Namespace
868: 	if len(service.Attributes.ExportTo) == 0 {
869: 		if ps.exportToDefaults.service[visibility.Private] {
870: 			return ns == namespace
871: 		} else if ps.exportToDefaults.service[visibility.Public] {
872: 			return true
873: 		}
874: 	}
875: 
876: 	return service.Attributes.ExportTo[visibility.Public] ||
877: 		(service.Attributes.ExportTo[visibility.Private] && ns == namespace) ||
878: 		service.Attributes.ExportTo[visibility.Instance(namespace)]
879: }
