905: // getSidecarScope returns a SidecarScope object associated with the
906: // proxy. The SidecarScope object is a semi-processed view of the service
907: // registry, and config state associated with the sidecar crd. The scope contains
908: // a set of inbound and outbound listeners, services/configs per listener,
909: // etc. The sidecar scopes are precomputed in the initSidecarContext
910: // function based on the Sidecar API objects in each namespace. If there is
911: // no sidecar api object, a default sidecarscope is assigned to the
912: // namespace which enables connectivity to all services in the mesh.
913: //
914: // Callers can check if the sidecarScope is from user generated object or not
915: // by checking the sidecarScope.Config field, that contains the user provided config
916: func (ps *PushContext) getSidecarScope(proxy *Proxy, workloadLabels labels.Collection) *SidecarScope {
917: 	// Find the most specific matching sidecar config from the proxy's
918: 	// config namespace If none found, construct a sidecarConfig on the fly
919: 	// that allows the sidecar to talk to any namespace (the default
920: 	// behavior in the absence of sidecars).
921: 	if sidecars, ok := ps.sidecarIndex.sidecarsByNamespace[proxy.ConfigNamespace]; ok {
922: 		// TODO: logic to merge multiple sidecar resources
923: 		// Currently we assume that there will be only one sidecar config for a namespace.
924: 		if proxy.Type == Router {
925: 			for _, wrapper := range sidecars {
926: 				// Gateways should just have a default scope with egress: */*
927: 				if wrapper.Sidecar == nil {
928: 					return wrapper
929: 				}
930: 			}
931: 		}
932: 		if proxy.Type == SidecarProxy {
933: 			for _, wrapper := range sidecars {
934: 				if wrapper.Sidecar != nil {
935: 					sidecar := wrapper.Sidecar
936: 					// if there is no workload selector, the config applies to all workloads
937: 					// if there is a workload selector, check for matching workload labels
938: 					if sidecar.GetWorkloadSelector() != nil {
939: 						workloadSelector := labels.Instance(sidecar.GetWorkloadSelector().GetLabels())
940: 						// exclude workload selector that not match
941: 						if !workloadLabels.IsSupersetOf(workloadSelector) {
942: 							continue
943: 						}
944: 					}
945: 
946: 					// it is guaranteed sidecars with selectors are put in front
947: 					// and the sidecars are sorted by creation timestamp,
948: 					// return exact/wildcard matching one directly
949: 					return wrapper
950: 				}
951: 				// this happens at last, it is the default sidecar scope
952: 				return wrapper
953: 			}
954: 		}
955: 	}
956: 
957: 	// We didn't have a Sidecar in the namespace. This means we should use the default - either an implicit
958: 	// default selecting everything, or pulling from the root namespace.
959: 	ps.sidecarIndex.defaultSidecarMu.Lock()
960: 	defer ps.sidecarIndex.defaultSidecarMu.Unlock()
961: 	if proxy.Type == Router {
962: 		sc, f := ps.sidecarIndex.gatewayDefaultSidecarsByNamespace[proxy.ConfigNamespace]
963: 		if f {
964: 			// We have already computed the scope for this namespace, just fetch it
965: 			return sc
966: 		}
967: 		computed := DefaultSidecarScopeForNamespace(ps, proxy.ConfigNamespace)
968: 		ps.sidecarIndex.gatewayDefaultSidecarsByNamespace[proxy.ConfigNamespace] = computed
969: 		return computed
970: 	}
971: 	sc, f := ps.sidecarIndex.computedSidecarsByNamespace[proxy.ConfigNamespace]
972: 	if f {
973: 		// We have already computed the scope for this namespace, just fetch it
974: 		return sc
975: 	}
976: 	// We need to compute this namespace
977: 	var computed *SidecarScope
978: 	if ps.sidecarIndex.rootConfig != nil {
979: 		computed = ConvertToSidecarScope(ps, ps.sidecarIndex.rootConfig, proxy.ConfigNamespace)
980: 	} else {
981: 		computed = DefaultSidecarScopeForNamespace(ps, proxy.ConfigNamespace)
982: 		// Even though we are a sidecar, we can store this as a gateway one since it could be used by a gateway
983: 		ps.sidecarIndex.gatewayDefaultSidecarsByNamespace[proxy.ConfigNamespace] = computed
984: 	}
985: 	ps.sidecarIndex.computedSidecarsByNamespace[proxy.ConfigNamespace] = computed
986: 	return computed
987: }
