1068: func (ps *PushContext) getExportedDestinationRuleFromNamespace(owningNamespace string, hostname host.Name, clientNamespace string) []*config.Config {
1069: 	if ps.destinationRuleIndex.exportedByNamespace[owningNamespace] != nil {
1070: 		if specificHostname, ok := MostSpecificHostMatch(hostname,
1071: 			ps.destinationRuleIndex.exportedByNamespace[owningNamespace].destRules,
1072: 		); ok {
1073: 			// Check if the dest rule for this host is actually exported to the proxy's (client) namespace
1074: 			exportToMap := ps.destinationRuleIndex.exportedByNamespace[owningNamespace].exportTo[specificHostname]
1075: 			if len(exportToMap) == 0 || exportToMap[visibility.Public] || exportToMap[visibility.Instance(clientNamespace)] {
1076: 				if features.EnableDestinationRuleInheritance {
1077: 					var parent *config.Config
1078: 					// client inherits global DR from its own namespace, not from the exported DR's owning namespace
1079: 					// grab the client namespace DR or mesh if none exists
1080: 					if parent = ps.destinationRuleIndex.inheritedByNamespace[clientNamespace]; parent == nil {
1081: 						parent = ps.destinationRuleIndex.inheritedByNamespace[ps.Mesh.RootNamespace]
1082: 					}
1083: 					var inheritedDrList []*config.Config
1084: 					for _, child := range ps.destinationRuleIndex.exportedByNamespace[owningNamespace].destRules[specificHostname] {
1085: 						inheritedDr := ps.inheritDestinationRule(parent, child)
1086: 						if inheritedDr != nil {
1087: 							inheritedDrList = append(inheritedDrList, inheritedDr)
1088: 						}
1089: 
1090: 					}
1091: 					return inheritedDrList
1092: 				}
1093: 				if dr, ok := ps.destinationRuleIndex.exportedByNamespace[owningNamespace].destRules[specificHostname]; ok {
1094: 					return dr
1095: 				}
1096: 			}
1097: 		}
1098: 	}
1099: 	return nil
1100: }
