30: // ConfigAffectsProxy checks if a pushEv will affect a specified proxy. That means whether the push will be performed
31: // towards the proxy.
32: func ConfigAffectsProxy(req *model.PushRequest, proxy *model.Proxy) bool {
33: 	// Empty changes means "all" to get a backward compatibility.
34: 	if len(req.ConfigsUpdated) == 0 {
35: 		return true
36: 	}
37: 
38: 	for config := range req.ConfigsUpdated {
39: 		affected := true
40: 
41: 		// Some configKinds only affect specific proxy types
42: 		if kindAffectedTypes, f := configKindAffectedProxyTypes[config.Kind]; f {
43: 			affected = false
44: 			for _, t := range kindAffectedTypes {
45: 				if t == proxy.Type {
46: 					affected = true
47: 					break
48: 				}
49: 			}
50: 		}
51: 
52: 		if affected && checkProxyDependencies(proxy, config) {
53: 			return true
54: 		}
55: 	}
56: 
57: 	return false
58: }
