76: // DefaultProxyNeedsPush check if a proxy needs push for this push event.
77: func DefaultProxyNeedsPush(proxy *model.Proxy, req *model.PushRequest) bool {
78: 	if ConfigAffectsProxy(req, proxy) {
79: 		return true
80: 	}
81: 
82: 	// If the proxy's service updated, need push for it.
83: 	if len(proxy.ServiceInstances) > 0 && req.ConfigsUpdated != nil {
84: 		svc := proxy.ServiceInstances[0].Service
85: 		if _, ok := req.ConfigsUpdated[model.ConfigKey{
86: 			Kind:      gvk.ServiceEntry,
87: 			Name:      string(svc.Hostname),
88: 			Namespace: svc.Attributes.Namespace,
89: 		}]; ok {
90: 			return true
91: 		}
92: 	}
93: 
94: 	return false
95: }
